namespace sv_7b495e876e424a849531889d27646322.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        var doctors = new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Patel",
            "Dr. Williams"
        };
        return Task.FromResult(doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateTime date)
    {
        var slots = new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        };
        return Task.FromResult(slots);
    }

    public Task<ValidationResult> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var result = new ValidationResult();

        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors["Email"] = "Account has outstanding balance";
        }

        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            result.Errors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        if (timeSlot == "10:00 AM")
        {
            result.Errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(result);
    }
}

public class ValidationResult
{
    public Dictionary<string, string> Errors { get; } = new();
    public bool IsValid => Errors.Count == 0;
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_7b495e876e424a849531889d27646322.Services
@using System.ComponentModel.DataAnnotations
@inject AppointmentService AppointmentService

<h3>Book Appointment</h3>

<EditForm Model="@model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    <h4>Step 1: Patient Information</h4>

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="model.PatientName" />
        <ValidationMessage For="() => model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
        <ValidationMessage For="() => model.Email" />
        @if (serverErrors.ContainsKey("Email"))
        {
            <div class="validation-message">@serverErrors["Email"]</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="model.Phone" />
        <ValidationMessage For="() => model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => model.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">Next</button>
    }

    @if (showStep2)
    {
        <hr />
        <h4>Step 2: Appointment Details</h4>

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-select" @bind-Value="model.Doctor" @bind-Value:after="OnDoctorOrDateChanged">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.Doctor" />
            @if (serverErrors.ContainsKey("Doctor"))
            {
                <div class="validation-message">@serverErrors["Doctor"]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="model.AppointmentDate" @bind-Value:after="OnDoctorOrDateChanged" />
            <ValidationMessage For="() => model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in timeSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.TimeSlot" />
            @if (serverErrors.ContainsKey("TimeSlot"))
            {
                <div class="validation-message">@serverErrors["TimeSlot"]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="model.ReasonForVisit" />
            <ValidationMessage For="() => model.ReasonForVisit" />
        </div>

        <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability">Check Availability</button>
        <button type="submit" class="btn btn-success" disabled="@(!availabilityChecked)">Book Appointment</button>

        @if (bookingConfirmed)
        {
            <div class="alert alert-success mt-3">Appointment booked successfully!</div>
        }
    }
</EditForm>

@code {
    private AppointmentModel model = new();
    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();
    private bool showStep2;
    private bool availabilityChecked;
    private bool bookingConfirmed;
    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(model);
        var validationResults = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
        var isStep1Valid = Validator.TryValidateProperty(model.PatientName, new ValidationContext(model) { MemberName = nameof(model.PatientName) }, validationResults)
            & Validator.TryValidateProperty(model.Email, new ValidationContext(model) { MemberName = nameof(model.Email) }, validationResults)
            & Validator.TryValidateProperty(model.Phone, new ValidationContext(model) { MemberName = nameof(model.Phone) }, validationResults)
            & Validator.TryValidateProperty(model.InsuranceProvider, new ValidationContext(model) { MemberName = nameof(model.InsuranceProvider) }, validationResults);

        if (isStep1Valid)
        {
            showStep2 = true;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityChecked = false;
        serverErrors.Clear();

        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate != default)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(model.Doctor, model.AppointmentDate);
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityChecked = false;

        var result = await AppointmentService.ValidatePatientAsync(
            model.Email,
            model.InsuranceProvider,
            model.Doctor,
            model.TimeSlot);

        if (!result.IsValid)
        {
            foreach (var error in result.Errors)
            {
                serverErrors[error.Key] = error.Value;
            }
            return;
        }

        availabilityChecked = true;
    }

    private void HandleSubmit()
    {
        if (availabilityChecked)
        {
            bookingConfirmed = true;
        }
    }

    public class AppointmentModel
    {
        [Required(ErrorMessage = "Patient name is required")]
        public string PatientName { get; set; } = "";

        [Required(ErrorMessage = "Email is required")]
        [EmailAddress(ErrorMessage = "Invalid email format")]
        public string Email { get; set; } = "";

        [Required(ErrorMessage = "Phone is required")]
        [Phone(ErrorMessage = "Invalid phone format")]
        public string Phone { get; set; } = "";

        [Required(ErrorMessage = "Insurance provider is required")]
        public string InsuranceProvider { get; set; } = "";

        [Required(ErrorMessage = "Doctor is required")]
        public string Doctor { get; set; } = "";

        [Required(ErrorMessage = "Date is required")]
        [FutureDate(ErrorMessage = "Date must be in the future")]
        public DateTime AppointmentDate { get; set; }

        [Required(ErrorMessage = "Time slot is required")]
        public string TimeSlot { get; set; } = "";

        [Required(ErrorMessage = "Reason for visit is required")]
        [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer")]
        public string ReasonForVisit { get; set; } = "";
    }

    public class FutureDateAttribute : ValidationAttribute
    {
        public override bool IsValid(object? value)
        {
            if (value is DateTime date)
            {
                return date.Date > DateTime.Today;
            }
            return false;
        }
    }
}

